def merge_sorted_files(file1, file2):
    result = []
    i, j = 0, 0
    while i < len(file1) and j < len(file2):
        if file1[i] <= file2[j]:
            result.append(file1[i])
            i += 1
        else:
            result.append(file2[j])
            j += 1
    while i < len(file1):
        result.append(file1[i])
        i += 1
    while j < len(file2):
        result.append(file2[j])
        j += 1
    return result

